50	// InitOptions contains all configuration options for project initialization
51	type InitOptions struct {
52		Force               bool   // Force initialization even if config exists
53		NoGit               bool   // Skip git-related operations
54		Silent              bool   // Suppress all output except errors
55		SkipClaudeInjection bool   // Skip injecting meta-prompts into CLAUDE.md
56		Repository          string // Custom repository URL (overrides default)
57		Branch              string // Custom repository branch (overrides default)
58		DDxVersion          string // Binary version to stamp into versions.yaml
59	}
