61	// Command registration is now handled by command_factory.go
62	// This file contains the CLI interface layer and pure business logic functions
63	
64	// InitResult contains the result of an initialization operation
65	type InitResult struct {
66		ConfigCreated bool
67		LibraryExists bool
68		Config        *config.Config
69	}
