71	// runInit implements the CLI interface layer for the init command
72	func (f *CommandFactory) runInit(cmd *cobra.Command, args []string) error {
73		// Extract flags from cobra.Command
74		initForce, _ := cmd.Flags().GetBool("force")
75		initNoGit, _ := cmd.Flags().GetBool("no-git")
76		initSilent, _ := cmd.Flags().GetBool("silent")
77		initSkipClaude, _ := cmd.Flags().GetBool("skip-claude-injection")
78		initRepository, _ := cmd.Flags().GetString("repository")
79		initBranch, _ := cmd.Flags().GetString("branch")
80	
81		// Create options struct for business logic
82		opts := InitOptions{
83			Force:               initForce,
84			NoGit:               initNoGit,
85			Silent:              initSilent,
86			SkipClaudeInjection: initSkipClaude,
87			Repository:          initRepository,
88			Branch:              initBranch,
89			DDxVersion:          f.Version,
90		}
91	
92		// Handle user output
93		if !opts.Silent {
94			_, _ = fmt.Fprint(cmd.OutOrStdout(), "🚀 Initializing DDx in current project...\n")
95			_, _ = fmt.Fprintln(cmd.OutOrStdout())
96		}
97	
98		// Call pure business logic function
99		_, err := initProject(f.WorkingDir, opts)
100		if err != nil {
101			cmd.SilenceUsage = true
102			return err
103		}
104	
105		// Handle user output based on results
106		if !opts.Silent {
107			_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx initialized successfully!\n")
108			_, _ = fmt.Fprintln(cmd.OutOrStdout())
109			_, _ = fmt.Fprint(cmd.OutOrStdout(), "Next steps:\n")
110			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx install helix   - Install HELIX workflow (optional)\n")
111			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx doctor          - Check installation health\n")
112			_, _ = fmt.Fprintln(cmd.OutOrStdout())
113		}
114	
115		return nil
116	}
