118	// initProject is the pure business logic function for project initialization
119	func initProject(workingDir string, opts InitOptions) (*InitResult, error) {
120		result := &InitResult{}
121	
122		// Validate git repository unless --no-git flag is used
123		if !opts.NoGit {
124			if err := validateGitRepo(workingDir); err != nil {
125				return nil, NewExitError(1, err.Error())
126			}
127		}
128	
129		// Guard against running inside an execute-bead context.
130		if os.Getenv("DDX_EXECUTE_BEAD_ID") != "" {
131			return nil, NewExitError(1,
132				"ddx init cannot be run inside an execute-bead context (DDX_EXECUTE_BEAD_ID is set)")
133		}
134		// Guard against running inside an execute-bead worktree. These are isolated
135		// execution environments under .ddx/.execute-bead-wt-*; running ddx init
136		// inside one would overwrite the project's .ddx/ config and beads.jsonl.
137		if isExecuteBeadWorktree(workingDir) {
138			return nil, NewExitError(1,
139				"ddx init cannot be run inside an execute-bead worktree (.ddx/.execute-bead-wt-*)")
140		}
141	
142		// Guard against nested workspaces: if a parent directory already has a
143		// .ddx/ workspace, refuse to create a second one in a subdirectory.
144		// This prevents the split-tracker bug where commands from different
145		// directories operate on different .ddx/beads.jsonl files.
146		if parent := findParentDDxWorkspace(workingDir); parent != "" {
147			return nil, NewExitError(1, fmt.Sprintf(
148				".ddx/ workspace already exists at %s. "+
149					"DDx anchors to the git repository root; run commands from any directory.",
150				parent))
151		}
152	
153		// Check if config already exists
154		configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
155		if _, err := os.Stat(configPath); err == nil {
156			if !opts.Force {
157				// Config exists and --force not used - exit code 2 per contract
158				return nil, NewExitError(2, ".ddx/config.yaml already exists. Use --force to overwrite.")
159			}
160			// With --force flag, we proceed to overwrite without backup
161		}
162	
163		// Check if library path exists using working directory
164		cfg, err := config.LoadWithWorkingDir(workingDir)
165		libraryExists := true
166		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
167			libraryExists = false
168		} else if _, err := os.Stat(filepath.Join(workingDir, cfg.Library.Path)); os.IsNotExist(err) {
169			libraryExists = false
170		}
171		result.LibraryExists = libraryExists
172	
173		// Create configuration with defaults
174		localConfig := createProjectConfig()
175	
176		// Apply default values (including repository settings)
177		localConfig.ApplyDefaults()
178	
179		// Add validation during creation
180		if err := validateConfiguration(localConfig); err != nil {
181			return nil, NewExitError(1, fmt.Sprintf("Configuration validation failed: %v", err))
182		}
183	
184		// Try to load existing config to preserve settings (even if library doesn't exist yet)
185		if cfg != nil && err == nil {
186			// Note: Version is NOT copied - always upgrade to current version via ApplyDefaults
187			// Copy library settings if they exist (unless overridden by flags)
188			if cfg.Library != nil && localConfig.Library != nil {
189				if cfg.Library.Path != "" {
190					localConfig.Library.Path = cfg.Library.Path
191				}
192				if cfg.Library.Repository != nil && localConfig.Library.Repository != nil {
193					// Only copy existing values if not overridden by flags
194					if opts.Repository == "" && cfg.Library.Repository.URL != "" {
195						localConfig.Library.Repository.URL = cfg.Library.Repository.URL
196					}
197					if opts.Branch == "" && cfg.Library.Repository.Branch != "" {
198						localConfig.Library.Repository.Branch = cfg.Library.Repository.Branch
199					}
200				}
201			}
202		}
203	
204		// Apply flag overrides AFTER loading existing config (flags have highest priority)
205		if opts.Repository != "" {
206			if localConfig.Library == nil {
207				localConfig.Library = &config.LibraryConfig{}
208			}
209			if localConfig.Library.Repository == nil {
210				localConfig.Library.Repository = &config.RepositoryConfig{}
211			}
212			localConfig.Library.Repository.URL = opts.Repository
213		}
214		if opts.Branch != "" {
215			if localConfig.Library == nil {
216				localConfig.Library = &config.LibraryConfig{}
217			}
218			if localConfig.Library.Repository == nil {
219				localConfig.Library.Repository = &config.RepositoryConfig{}
220			}
221			localConfig.Library.Repository.Branch = opts.Branch
222		}
223	
224		// Create .ddx directory first
225		localDDxPath := filepath.Join(workingDir, ".ddx")
226		if err := os.MkdirAll(localDDxPath, 0755); err != nil {
227			return nil, NewExitError(1, fmt.Sprintf("Failed to create .ddx directory: %v", err))
228		}
229	
230		// Save local configuration using ConfigLoader
231		loader, err := config.NewConfigLoaderWithWorkingDir(workingDir)
232		if err != nil {
233			return nil, NewExitError(1, fmt.Sprintf("Failed to create config loader: %v", err))
234		}
235		if err := loader.SaveConfig(localConfig, ".ddx/config.yaml"); err != nil {
236			return nil, NewExitError(1, fmt.Sprintf("Failed to save configuration: %v", err))
237		}
238		result.ConfigCreated = true
239	
240		if err := ensureProjectGitignoreRules(workingDir, initGitignoreRules); err != nil {
241			return nil, NewExitError(1, fmt.Sprintf("Failed to update .gitignore: %v", err))
242		}
243	
244		// Create library directory structure (offline-safe — plugin install may fail).
245		libraryPath := filepath.Join(workingDir, localConfig.Library.Path)
246		for _, sub := range []string{"prompts", "personas", "patterns", "templates", "configs"} {
247			_ = os.MkdirAll(filepath.Join(libraryPath, sub), 0755)
248		}
249	
250		// Create .ddx/skills/ in project for bootstrap skills
251		projectSkillsDir := filepath.Join(workingDir, ".ddx", "skills")
252		if err := os.MkdirAll(projectSkillsDir, 0755); err != nil {
253			_, _ = fmt.Fprintf(os.Stderr, "Warning: could not create .ddx/skills directory: %v\n", err)
254		}
255	
256		// Copy bootstrap skills to .ddx/skills/, .agents/skills/, and .claude/skills/
257		// All as real files (not symlinks) so they're git-trackable.
258		// Stale pre-consolidation ddx-* skill dirs (ddx-bead, ddx-run, etc.) are
259		// removed first so harnesses don't see drifted skills.
260		bootstrapSkillNames := []string{"ddx"}
261		for _, dir := range []string{
262			filepath.Join(workingDir, ".ddx", "skills"),
263			filepath.Join(workingDir, ".agents", "skills"),
264			filepath.Join(workingDir, ".claude", "skills"),
265		} {
266			_ = os.MkdirAll(dir, 0755)
267			cleanupBootstrapSkills(dir, bootstrapSkillNames)
268		}
269		// .agents/skills/ + .claude/skills/ via shared installer.
270		if err := skills.Install(skills.SkillFiles, workingDir, skills.Options{Force: opts.Force}); err != nil {
271			_, _ = fmt.Fprintf(os.Stderr, "Warning: skill install failed: %v\n", err)
272		}
273		// .ddx/skills/ stays bootstrap-only (plugin skills do NOT register here).
274		registerBootstrapDDxSkills(workingDir, opts.Force)
275	
276		// Auto-install the default ddx plugin (library resources).
277		// Non-fatal: if offline or install fails, warn and continue.
278		reg := registry.BuiltinRegistry()
279		if pkg, err := reg.Find("ddx"); err == nil {
280			var oldFiles []string
281			if state, _ := registry.LoadState(); state != nil {
282				if old := state.FindInstalled(pkg.Name); old != nil {
283					oldFiles = append([]string{}, old.Files...)
284				}
285			}
286	
287			if entry, installErr := registry.InstallPackage(pkg, workingDir); installErr != nil {
288				_, _ = fmt.Fprintf(os.Stderr, "Warning: could not install default library: %v\n", installErr)
289			} else {
290				_ = removeStaleFilesFromInstall(oldFiles, entry.Files)
291	
292				state, _ := registry.LoadState()
293				if state == nil {
294					state = &registry.InstalledState{}
295				}
296				state.AddOrUpdate(entry)
297				_ = registry.SaveState(state)
298			}
299		}
300	
301		// Write .ddx/versions.yaml (system-managed, tracks binary version)
302		writeProjectVersions(workingDir, opts.DDxVersion)
303	
304		if !opts.NoGit {
305			// Inject initial meta-prompt if the prompt file actually exists (unless explicitly skipped)
306			if !opts.SkipClaudeInjection {
307				if err := injectInitialMetaPrompt(localConfig, workingDir); err != nil {
308					// Don't fail - meta-prompt is optional enhancement
309					// Only warn if the specific prompt file exists but has issues
310					promptPath := localConfig.GetMetaPrompt()
311					if promptPath != "" {
312						fullPromptPath := filepath.Join(workingDir, localConfig.Library.Path, promptPath)
313						if _, statErr := os.Stat(fullPromptPath); statErr == nil {
314							_, _ = fmt.Fprintf(os.Stderr, "Warning: Failed to inject meta-prompt: %v\n", err)
315						}
316					}
317				}
318			}
319	
320			// Generate AGENTS.md with guidance for AI agents working in this repo.
321			generateAgentsMD(workingDir)
322	
323			// Commit config and versions files
324			ctx := context.Background()
325			gitAdd := gitpkg.Command(ctx, workingDir, "add", ".ddx/config.yaml", ".ddx/versions.yaml", "AGENTS.md", ".gitignore")
326			if err := gitAdd.Run(); err != nil {
327				return nil, NewExitError(1, fmt.Sprintf("Failed to stage config file: %v", err))
328			}
329	
330			gitCommit := gitpkg.Command(ctx, workingDir, "commit", "-m", "chore: add DDx configuration")
331			if err := gitCommit.Run(); err != nil {
332				return nil, NewExitError(1, fmt.Sprintf("Failed to commit config file: %v", err))
333			}
334	
335			// Enable per-worktree git config so that `git config --local` inside
336			// linked worktrees (e.g. execute-bead worktrees) writes to a
337			// worktree-specific file rather than the shared .git/config. This
338			// prevents agents from accidentally corrupting repo-level settings like
339			// core.bare when running in an isolated worktree.
340			gitWorktreeCfg := gitpkg.Command(ctx, workingDir, "config", "extensions.worktreeConfig", "true")
341			_ = gitWorktreeCfg.Run() // best-effort; older git versions may not support it
342		}
343	
344		// Store config for CLI layer to use for sync setup
345		result.Config = localConfig
346	
347		// Configuration already saved above
348	
349		return result, nil
350	}
