352	// writeProjectVersions writes .ddx/versions.yaml with the current binary version.
353	// This file is system-managed and committed to git for version gating.
354	func writeProjectVersions(workingDir, ddxVersion string) {
355		if ddxVersion == "" || ddxVersion == "dev" {
356			ddxVersion = "dev"
357		}
358		versionsPath := filepath.Join(workingDir, ".ddx", "versions.yaml")
359		content := fmt.Sprintf("ddx_version: %q\n", ddxVersion)
360		if err := os.WriteFile(versionsPath, []byte(content), 0644); err != nil {
361			_, _ = fmt.Fprintf(os.Stderr, "Warning: could not write .ddx/versions.yaml: %v\n", err)
362		}
363	}
364	
365	// readProjectVersions reads ddx_version from .ddx/versions.yaml.
366	// Returns empty string if the file doesn't exist or can't be parsed.
367	func readProjectVersions(workingDir string) string {
368		versionsPath := filepath.Join(workingDir, ".ddx", "versions.yaml")
369		data, err := os.ReadFile(versionsPath)
370		if err != nil {
371			return ""
372		}
373		// Simple parse: look for ddx_version: "x.y.z" or ddx_version: x.y.z
374		for _, line := range strings.Split(string(data), "\n") {
375			line = strings.TrimSpace(line)
376			if strings.HasPrefix(line, "ddx_version:") {
377				val := strings.TrimPrefix(line, "ddx_version:")
378				val = strings.TrimSpace(val)
379				val = strings.Trim(val, `"'`)
380				return val
381			}
382		}
383		return ""
384	}
