386	func cleanupBootstrapSkills(targetDir string, keep []string) {
387		entries, err := os.ReadDir(targetDir)
388		if err != nil {
389			return
390		}
391	
392		keepSet := make(map[string]bool, len(keep))
393		for _, name := range keep {
394			keepSet[name] = true
395		}
396	
397		for _, entry := range entries {
398			name := entry.Name()
399			if !strings.HasPrefix(name, "ddx-") {
400				continue
401			}
402			if keepSet[name] {
403				continue
404			}
405	
406			skillDir := filepath.Join(targetDir, name)
407			if _, err := os.Stat(filepath.Join(skillDir, "SKILL.md")); err != nil {
408				continue
409			}
410	
411			_ = os.RemoveAll(skillDir)
412		}
413	}
