415	// registerBootstrapDDxSkills copies the embedded `ddx` skill tree into
416	// <workingDir>/.ddx/skills/ as real files. This path is bootstrap-only —
417	// plugin skills do NOT register here. Cleanup of stale pre-consolidation
418	// dirs is done by the caller.
419	func registerBootstrapDDxSkills(workingDir string, force bool) {
420		targetDir := filepath.Join(workingDir, ".ddx", "skills")
421		_ = os.MkdirAll(targetDir, 0755)
422	
423		err := fs.WalkDir(skills.SkillFiles, ".", func(path string, d fs.DirEntry, err error) error {
424			if err != nil || path == "." {
425				return nil
426			}
427			destPath := filepath.Join(targetDir, path)
428			if d.IsDir() {
429				_ = os.MkdirAll(destPath, 0755)
430				return nil
431			}
432			if !force {
433				if _, statErr := os.Stat(destPath); statErr == nil {
434					return nil
435				}
436			}
437			data, readErr := skills.SkillFiles.ReadFile(path)
438			if readErr != nil {
439				_, _ = fmt.Fprintf(os.Stderr, "Warning: could not read embedded skill %s: %v\n", path, readErr)
440				return nil
441			}
442			if writeErr := os.WriteFile(destPath, data, 0644); writeErr != nil {
443				_, _ = fmt.Fprintf(os.Stderr, "Warning: could not write skill file %s: %v\n", destPath, writeErr)
444			}
445			return nil
446		})
447		if err != nil {
448			_, _ = fmt.Fprintf(os.Stderr, "Warning: bootstrap skill registration failed: %v\n", err)
449		}
450	}
