474	func ensureProjectGitignoreRules(workingDir string, rules []string) error {
475		if len(rules) == 0 {
476			return nil
477		}
478		path := filepath.Join(workingDir, ".gitignore")
479		var content string
480		if raw, err := os.ReadFile(path); err == nil {
481			content = string(raw)
482		} else if !os.IsNotExist(err) {
483			return err
484		}
485	
486		trimmed := strings.TrimRight(content, "\n")
487		var missing []string
488		for _, rule := range rules {
489			rule = strings.TrimSpace(rule)
490			if rule == "" || containsExactLine(trimmed, rule) {
491				continue
492			}
493			missing = append(missing, rule)
494		}
495		if len(missing) == 0 {
496			return nil
497		}
498	
499		updated := trimmed
500		if updated != "" {
501			updated += "\n"
502		}
503		updated += "# DDx runtime scratch\n"
504		for _, rule := range missing {
505			updated += rule + "\n"
506		}
507		return os.WriteFile(path, []byte(updated), 0o644)
508	}
509	
510	func containsExactLine(content, target string) bool {
511		for _, line := range strings.Split(content, "\n") {
512			if strings.TrimSpace(line) == target {
513				return true
514			}
515		}
516		return false
517	}
