519	// validateGitRepo is the pure business logic for git repository validation
520	func validateGitRepo(workingDir string) error {
521		// Use git rev-parse --git-dir to check if we're in a git repository.
522		// gitpkg.Command strips inherited GIT_DIR / GIT_WORK_TREE so the check
523		// reflects the actual directory, not an inherited git context.
524		gitCmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--git-dir")
525		gitCmd.Stderr = nil // Suppress error output
526		if err := gitCmd.Run(); err != nil {
527			return fmt.Errorf("Error: ddx init must be run inside a git repository. Please run 'git init' first")
528		}
529	
530		return nil
531	}
532	
533	// findParentDDxWorkspace walks up from dir looking for a .ddx/ directory in
534	// any ancestor within the same git repository. Returns the ancestor path if
535	// found, or "" if none exists. Only checks within the git repo boundary to
536	// avoid false positives from stale .ddx/ directories elsewhere on the system.
537	func findParentDDxWorkspace(dir string) string {
538		abs, err := filepath.Abs(dir)
539		if err != nil {
540			return ""
541		}
542	
543		// Determine the git root to bound the upward walk.
544		gitRoot := gitpkg.FindProjectRoot(abs)
545		if gitRoot == abs {
546			// dir is already the git root — no parent to check within the repo.
547			return ""
548		}
549	
550		// Walk up from the parent to the git root (inclusive).
551		current := filepath.Dir(abs)
552		for {
553			candidate := filepath.Join(current, ".ddx")
554			if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
555				return current
556			}
557			if current == gitRoot {
558				break
559			}
560			parent := filepath.Dir(current)
561			if parent == current {
562				break // filesystem root — shouldn't happen if gitRoot is set
563			}
564			current = parent
565		}
566		return ""
567	}
568	
569	// isExecuteBeadWorktree reports whether dir is inside an execute-bead
570	// worktree. Detects both the legacy in-repo location (.execute-bead-wt-*
571	// under .ddx/) and the current out-of-repo location ($TMPDIR/ddx-exec-wt/
572	// or DDX_EXEC_WT_DIR override). These are linked git worktrees and must
573	// not be re-initialized.
574	func isExecuteBeadWorktree(dir string) bool {
575		abs, err := filepath.Abs(dir)
576		if err != nil {
577			return false
578		}
579		slash := filepath.ToSlash(abs)
580		// Legacy: a path component starting with .execute-bead-wt-.
581		for _, part := range strings.Split(slash, "/") {
582			if strings.HasPrefix(part, ".execute-bead-wt-") {
583				return true
584			}
585		}
586		// Current: $TMPDIR/ddx-exec-wt/ (or DDX_EXEC_WT_DIR) container.
587		tmpContainer := filepath.ToSlash(filepath.Join(os.TempDir(), "ddx-exec-wt"))
588		if strings.HasPrefix(slash, tmpContainer+"/") {
589			return true
590		}
591		if override := os.Getenv("DDX_EXEC_WT_DIR"); override != "" {
592			if strings.HasPrefix(slash, filepath.ToSlash(override)+"/") {
593				return true
594			}
595		}
596		return false
597	}
