687	// generateAgentsMD injects (or refreshes) the DDx-owned block in AGENTS.md.
688	// If AGENTS.md does not exist, it is created containing only the block.
689	// If AGENTS.md exists with markers, the content between markers is replaced
690	// and everything outside is preserved. If AGENTS.md exists without markers,
691	// the block is appended to the end.
692	func generateAgentsMD(workingDir string) {
693		agentsPath := filepath.Join(workingDir, "AGENTS.md")
694		block := ddxAgentsBlock()
695	
696		existing, err := os.ReadFile(agentsPath)
697		if err != nil {
698			// File doesn't exist — create with just the block.
699			_ = os.WriteFile(agentsPath, []byte(block), 0644)
700			return
701		}
702	
703		content := string(existing)
704		startIdx := strings.Index(content, agentsMarkerStart)
705		endIdx := strings.Index(content, agentsMarkerEnd)
706	
707		if startIdx == -1 || endIdx == -1 || endIdx < startIdx {
708			// Markers not present (or malformed). Append block to end.
709			separator := ""
710			if !strings.HasSuffix(content, "\n") {
711				separator = "\n"
712			}
713			if !strings.HasSuffix(content, "\n\n") {
714				separator += "\n"
715			}
716			updated := content + separator + block
717			_ = os.WriteFile(agentsPath, []byte(updated), 0644)
718			return
719		}
720	
721		// Markers present — replace the block between them.
722		endOfEndMarker := endIdx + len(agentsMarkerEnd)
723		// Include trailing newline after the end marker if present.
724		if endOfEndMarker < len(content) && content[endOfEndMarker] == '\n' {
725			endOfEndMarker++
726		}
727		updated := content[:startIdx] + block + content[endOfEndMarker:]
728		_ = os.WriteFile(agentsPath, []byte(updated), 0644)
729	}
