327	// UninstallPackage removes files recorded in the entry.
328	func UninstallPackage(entry *InstalledEntry) error {
329		var errs []string
330		for _, f := range entry.Files {
331			expanded := ExpandHome(f)
332			if err := os.Remove(expanded); err != nil && !os.IsNotExist(err) {
333				errs = append(errs, fmt.Sprintf("removing %s: %v", f, err))
334			}
335		}
336		if len(errs) > 0 {
337			return fmt.Errorf("uninstall errors: %s", strings.Join(errs, "; "))
338		}
339		return nil
340	}
