342	// githubTarballURL builds a GitHub release tarball URL from a repo URL and version tag.
343	// e.g. "https://github.com/owner/repo" + "1.0.0" →
344	//
345	//	"https://github.com/owner/repo/archive/refs/tags/v1.0.0.tar.gz"
346	func githubTarballURL(repoURL, version string) string {
347		tag := version
348		if !strings.HasPrefix(tag, "v") {
349			tag = "v" + tag
350		}
351		return strings.TrimRight(repoURL, "/") + "/archive/refs/tags/" + tag + ".tar.gz"
352	}
353	
354	// downloadAndExtract downloads a .tar.gz from url into destDir and returns
355	// the path of the single top-level directory extracted from the archive.
356	func downloadAndExtract(url, destDir string) (string, error) {
357		resp, err := http.Get(url) //nolint:noctx
358		if err != nil {
359			return "", fmt.Errorf("fetching %s: %w", url, err)
360		}
361		defer func() { _ = resp.Body.Close() }()
362	
363		if resp.StatusCode != http.StatusOK {
364			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
365		}
366	
367		gz, err := gzip.NewReader(resp.Body)
368		if err != nil {
369			return "", fmt.Errorf("reading gzip: %w", err)
370		}
371		defer func() { _ = gz.Close() }()
372	
373		tr := tar.NewReader(gz)
374		var topDir string
375	
376		for {
377			hdr, err := tr.Next()
378			if err == io.EOF {
379				break
380			}
381			if err != nil {
382				return "", fmt.Errorf("reading tar: %w", err)
383			}
384	
385			// Sanitize path to prevent directory traversal.
386			clean := filepath.Clean(hdr.Name)
387			if strings.HasPrefix(clean, "..") {
388				continue
389			}
390	
391			dest := filepath.Join(destDir, clean)
392	
393			// Skip PAX global headers (GitHub tarballs include these).
394			if hdr.Typeflag == tar.TypeXGlobalHeader {
395				continue
396			}
397	
398			// Track the top-level directory name.
399			parts := strings.SplitN(clean, string(filepath.Separator), 2)
400			if topDir == "" && parts[0] != "" && parts[0] != "." {
401				topDir = parts[0]
402			}
403	
404			switch hdr.Typeflag {
405			case tar.TypeDir:
406				if err := os.MkdirAll(dest, 0755); err != nil {
407					return "", err
408				}
409			case tar.TypeReg:
410				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
411					return "", err
412				}
413				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
414				if err != nil {
415					return "", err
416				}
417				if _, err := io.Copy(f, tr); err != nil {
418					_ = f.Close()
419					return "", err
420				}
421				_ = f.Close()
422			case tar.TypeSymlink:
423				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
424					return "", err
425				}
426				_ = os.Remove(dest)
427				if err := os.Symlink(hdr.Linkname, dest); err != nil {
428					return "", err
429				}
430			}
431		}
432	
433		if topDir == "" {
434			return destDir, nil
435		}
436		return filepath.Join(destDir, topDir), nil
437	}
438	
439	// CopyScriptFromRoot copies a script from an installed plugin root to the
440	// target path. Exported for use by local install path.
441	func CopyScriptFromRoot(installedRoot string, mapping *InstallMapping) (string, error) {
442		files, err := copyMapping(installedRoot, mapping)
443		if err != nil {
444			return "", err
445		}
446		dst := ExpandHome(mapping.Target)
447		if info, err := os.Stat(dst); err == nil && !info.IsDir() {
448			_ = os.Chmod(dst, info.Mode()|0111)
449		}
450		if len(files) > 0 {
451			return files[0], nil
452		}
453		return dst, nil
454	}
455	
456	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
457	// If the source is a single file and the target does not end with a path
458	// separator, the target is treated as the exact destination file path.
459	// If the source is a directory (or target ends with /), files are copied
460	// into the target directory.
461	// Returns the list of destination files written.
462	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
463		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
464		dst := ExpandHome(mapping.Target)
465	
466		info, err := os.Stat(src)
467		if os.IsNotExist(err) {
468			// Source path doesn't exist in this repo — skip silently.
469			return nil, nil
470		}
471		if err != nil {
472			return nil, err
473		}
474	
475		var written []string
476	
477		if info.IsDir() {
478			// If dst is an existing symlink (e.g. from a prior --local install),
479			// remove it before creating the real directory.
480			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
481				if err := os.Remove(dst); err != nil {
482					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
483				}
484			}
485	
486			// Copy directory tree into dst (create dst as a directory).
487			if err := os.MkdirAll(dst, 0755); err != nil {
488				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
489			}
490	
491			// HELIX skills use symlinks, so resolve each entry via os.Stat.
492			entries, err := os.ReadDir(src)
493			if err != nil {
494				return nil, err
495			}
496			for _, e := range entries {
497				srcPath := filepath.Join(src, e.Name())
498				dstPath := filepath.Join(dst, e.Name())
499	
500				fi, err := os.Stat(srcPath)
501				if err != nil {
502					if recovered := recoverSkillDir(srcDir, src, e.Name()); recovered != "" {
503						srcPath = recovered
504						fi, err = os.Stat(srcPath)
505					}
506					if err != nil {
507						continue // skip unrecoverable broken symlinks
508					}
509				}
510	
511				if fi.IsDir() {
512					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
513					if subErr != nil {
514						return nil, subErr
515					}
516					written = append(written, subFiles...)
517				} else if fi.Mode().IsRegular() {
518					if err := copyFile(srcPath, dstPath); err != nil {
519						return nil, err
520					}
521					written = append(written, dstPath)
522				}
523			}
524		} else {
525			// Source is a single file. If target ends with /, copy into that
526			// directory using the source filename; otherwise treat target as
527			// the exact destination file path.
528			var dstFile string
529			if strings.HasSuffix(mapping.Target, "/") {
530				if err := os.MkdirAll(dst, 0755); err != nil {
531					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
532				}
533				dstFile = filepath.Join(dst, filepath.Base(src))
534			} else {
535				dstFile = dst
536			}
537			if err := copyFile(src, dstFile); err != nil {
538				return nil, err
539			}
540			written = append(written, dstFile)
541		}
542	
543		return written, nil
544	}
545	
546	// copyFile copies src to dst, creating parent directories as needed.
547	// Preserves the source file's permissions. If dst already exists (file,
548	// symlink, or directory), it is removed first.
549	func copyFile(src, dst string) error {
550		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
551			return err
552		}
553	
554		// Remove any existing file/symlink/directory at dst.
555		if _, err := os.Lstat(dst); err == nil {
556			if err := os.RemoveAll(dst); err != nil {
557				return fmt.Errorf("removing existing %s: %w", dst, err)
558			}
559		}
560	
561		srcInfo, err := os.Stat(src)
562		if err != nil {
563			return err
564		}
565	
566		in, err := os.Open(src)
567		if err != nil {
568			return err
569		}
570		defer func() { _ = in.Close() }()
571	
572		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
573		if err != nil {
574			return err
575		}
576		defer func() { _ = out.Close() }()
577	
578		_, err = io.Copy(out, in)
579		return err
580	}
581	
582	// downloadFile fetches url and writes it to dest.
583	func downloadFile(url, dest string) error {
584		resp, err := http.Get(url) //nolint:noctx
585		if err != nil {
586			return fmt.Errorf("fetching %s: %w", url, err)
587		}
588		defer func() { _ = resp.Body.Close() }()
589	
590		if resp.StatusCode != http.StatusOK {
591			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
592		}
593	
594		f, err := os.Create(dest)
595		if err != nil {
596			return err
597		}
598		defer func() { _ = f.Close() }()
599	
600		_, err = io.Copy(f, resp.Body)
601		return err
602	}
603	
604	// ExpandHome expands a leading ~ to the user's home directory.
605	func ExpandHome(path string) string {
606		if !strings.HasPrefix(path, "~") {
607			return path
608		}
609		home, err := os.UserHomeDir()
610		if err != nil {
611			return path
612		}
613		return filepath.Join(home, path[1:])
614	}
