2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strings"
8	
9		"gopkg.in/yaml.v3"
10	)
11	
12	const SupportedPackageAPIVersion = "1"
13	
14	// ValidationIssue represents one package or plugin validation problem.
15	type ValidationIssue struct {
16		Path    string
17		Message string
18	}
19	
20	func (i ValidationIssue) Error() string {
21		if i.Path == "" {
22			return i.Message
23		}
24		return fmt.Sprintf("%s: %s", i.Path, i.Message)
25	}
26	
27	type packageManifestRaw struct {
28		Name        string         `yaml:"name"`
29		Version     string         `yaml:"version"`
30		Description string         `yaml:"description"`
31		Type        string         `yaml:"type"`
32		Source      string         `yaml:"source"`
33		APIVersion  any            `yaml:"api_version"`
34		Install     PackageInstall `yaml:"install"`
35		Keywords    []string       `yaml:"keywords"`
36	}
37	
38	// knownManifestKeys is the set of top-level keys consumed by the current
39	// manifest schema. Any additional keys are preserved on Package.Extra so
40	// manifests written against newer api_versions round-trip without silent
41	// field loss.
42	var knownManifestKeys = map[string]struct{}{
43		"name":        {},
44		"version":     {},
45		"description": {},
46		"type":        {},
47		"source":      {},
48		"api_version": {},
49		"install":     {},
50		"keywords":    {},
51	}
52	
53	// LoadPackageManifest reads and validates package.yaml from root.
54	func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
55		manifestPath := filepath.Join(root, "package.yaml")
56		data, err := os.ReadFile(manifestPath)
57		if err != nil {
58			return nil, nil, err
59		}
60	
61		var raw packageManifestRaw
62		if err := yaml.Unmarshal(data, &raw); err != nil {
63			issue := ValidationIssue{
64				Path:    manifestPath,
65				Message: fmt.Sprintf("invalid YAML: %v", err),
66			}
67			return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
68		}
69	
70		// Also unmarshal into a free-form map so any keys not in the typed
71		// struct survive as Package.Extra. yaml.v3 returns
72		// map[string]any, preserving nested structure for round-trip.
73		var full map[string]any
74		if err := yaml.Unmarshal(data, &full); err != nil {
75			// If the typed unmarshal succeeded, this cannot realistically
76			// fail — but guard anyway.
77			issue := ValidationIssue{
78				Path:    manifestPath,
79				Message: fmt.Sprintf("invalid YAML: %v", err),
80			}
81			return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
82		}
83	
84		pkg, issues := validatePackageManifest(manifestPath, raw)
85		if pkg != nil {
86			if extra := extraManifestKeys(full); len(extra) > 0 {
87				pkg.Extra = extra
88			}
89		}
90		if len(issues) > 0 && pkg == nil {
91			return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
92		}
93		// Even when validation issues exist, return the partial package so callers
94		// can perform structural audits (symlinks, SKILL.md files) independently.
95		// However, if no package was returned at all, return an error so callers
96		// know something is fundamentally wrong.
97		if pkg == nil {
98			return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
99		}
100		return pkg, issues, nil
101	}
102	
103	// extraManifestKeys returns manifest keys that are not part of the current
104	// typed schema. Values are preserved as-is so callers can inspect them later.
105	func extraManifestKeys(full map[string]any) map[string]any {
106		if len(full) == 0 {
107			return nil
108		}
109		var extra map[string]any
110		for k, v := range full {
111			if _, known := knownManifestKeys[k]; known {
112				continue
113			}
114			if extra == nil {
115				extra = make(map[string]any, len(full))
116			}
117			extra[k] = v
118		}
119		return extra
120	}
121	
122	// LoadPackageManifestWithFallback reads package.yaml and falls back to the
123	// provided package when the manifest is missing.
124	func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
125		pkg, issues, err := LoadPackageManifest(root)
126		if err == nil {
127			// Return issues separately even when package is valid, so callers can
128			// detect schema problems while still using the package for structural audits.
129			if len(issues) > 0 {
130				return pkg, false, issues, nil
131			}
132			return pkg, false, nil, nil
133		}
134	
135		// If a partial package was returned (YAML parsed but validation issues exist),
136		// return it with the issues so callers can still use its structure.
137		if pkg != nil {
138			return pkg, false, issues, nil
139		}
140	
141		if os.IsNotExist(err) {
142			return fallback, true, nil, err
143		}
144	
145		if fallback != nil {
146			return fallback, false, issues, err
147		}
148		return nil, false, issues, err
149	}
150	
151	// validatePackageManifest validates required fields and returns a partial package
152	// even when validation issues are found. This ensures that structural audits
153	// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
154	func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
155		var issues []ValidationIssue
156	
157		name := strings.TrimSpace(raw.Name)
158		if name == "" {
159			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
160		}
161		version := strings.TrimSpace(raw.Version)
162		if version == "" {
163			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
164		}
165		description := strings.TrimSpace(raw.Description)
166		if description == "" {
167			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
168		}
169		pkgType, ok := parseManifestPackageType(raw.Type)
170		if !ok {
171			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
172		}
173		source := strings.TrimSpace(raw.Source)
174		if source == "" {
175			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
176		}
177	
178		apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
179		if apiIssue != "" {
180			issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
181		}
182	
183		// Always construct a partial package so structural audits can proceed.
184		// Validation issues are still collected and returned separately.
185		pkg := &Package{
186			Name:        name,
187			Version:     version,
188			Description: description,
189			Type:        pkgType,
190			Source:      source,
191			APIVersion:  apiVersion,
192			Install:     raw.Install,
193			Keywords:    append([]string(nil), raw.Keywords...),
194		}
195		return pkg, issues
196	}
197	
198	func parseManifestPackageType(rawType string) (PackageType, bool) {
199		switch PackageType(strings.TrimSpace(rawType)) {
200		case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
201			return PackageType(strings.TrimSpace(rawType)), true
202		default:
203			return "", false
204		}
205	}
206	
207	func parseAPIVersion(raw any) (string, string) {
208		if raw == nil {
209			return "", "missing required field `api_version`"
210		}
211	
212		value := strings.TrimSpace(fmt.Sprint(raw))
213		if value == "" {
214			return "", "missing required field `api_version`"
215		}
216		if value != SupportedPackageAPIVersion {
217			return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
218		}
219		return value, ""
220	}
221	
222	// JoinValidationIssues renders a slice of validation issues into a single
223	// semicolon-separated error string.
224	func JoinValidationIssues(issues []ValidationIssue) string {
225		msgs := make([]string, 0, len(issues))
226		for _, issue := range issues {
227			msgs = append(msgs, issue.Error())
228		}
229		return strings.Join(msgs, "; ")
230	}
231	
232	func defaultPackageRootTarget(name string) string {
233		return fmt.Sprintf(".ddx/plugins/%s", name)
234	}
