92	
93		if hint.Source == ExecutionIntentSourceBeadHint && hint.InferredPowerClass == PowerSmart && strings.TrimSpace(hint.SmartJustification) == "" {
94			findings = append(findings, ExecutionHintFinding{
95				Field:   "description",
96				Message: "bead uses power:smart but has no SMART JUSTIFICATION section",
97			})
98		}
99	
100		for _, pin := range hint.RejectedRoutePins {
101			findings = append(findings, durableRoutePinFinding(b.ID, pin))
102		}
103	
104		return findings
105	}
