107	func parsePowerLabel(raw string) (PowerClass, bool) {
108		l := strings.ToLower(strings.TrimSpace(raw))
109		if l == "" {
110			return "", false
111		}
112		powerClass, ok := strings.CutPrefix(l, "power:")
113		if !ok {
114			return "", false
115		}
116		switch strings.TrimSpace(powerClass) {
117		case string(PowerSmart):
118			return PowerSmart, true
119		case string(PowerStandard):
120			return PowerStandard, true
121		case string(PowerCheap):
122			return PowerCheap, true
123		default:
124			return "", false
125		}
126	}
